#include "interface.h"
#include <simdutf.h>
#include <string>
#include <vector>

namespace {

uint64_t checksum_bytes(const char* data, size_t len) {
    uint64_t hash = 1469598103934665603ULL;
    for (size_t i = 0; i < len; ++i) {
        hash ^= static_cast<uint64_t>(static_cast<unsigned char>(data[i]));
        hash *= 1099511628211ULL;
    }
    return hash;
}

} // namespace

uint64_t decode_checksum(const std::string& input) {
    // simdutf requires a buffer sized for the worst case
    const size_t max_binary_len = simdutf::maximal_binary_length_from_base64(input.data(), input.size());
    std::vector<char> buffer(max_binary_len);

    // decode the entire input at once
    size_t actual_len = simdutf::base64_to_binary(input.data(), input.size(), buffer.data(), simdutf::base64_default);

    // checksum the exact decoded bytes
    return checksum_bytes(buffer.data(), actual_len);
}
